import fs from 'node:fs'
import path from 'node:path'

import { fileURLToPath } from 'node:url'

import yaml from 'js-yaml'

const __filename = fileURLToPath(import.meta.url)
const __dirname = path.dirname(__filename)

const localesDir = path.resolve(__dirname, '../packages/i18n/src/locales')
const outputDir = path.resolve(__dirname, '../packages/i18n/src/dist-lite') // Temporary location
if (!fs.existsSync(outputDir))
  fs.mkdirSync(outputDir, { recursive: true })

function loadDir(dir) {
  const result = {}
  const entries = fs.readdirSync(dir, { withFileTypes: true })
  for (const entry of entries) {
    const fullPath = path.join(dir, entry.name)
    if (entry.isDirectory()) {
      result[entry.name] = loadDir(fullPath)
    }
    else if (entry.name.endsWith('.yaml')) {
      const name = entry.name.replace('.yaml', '')
      result[name] = yaml.load(fs.readFileSync(fullPath, 'utf8'))
    }
    else if (entry.name.endsWith('.ts') && entry.name !== 'index.ts') {
      // Basic support for TS files that export default objects
      // (This is a bit hacky but works for AIRI's structure)
      const content = fs.readFileSync(fullPath, 'utf8')
      if (content.includes('export default')) {
        // Skip for now, we'll manually handle the nesting
      }
    }
  }
  return result
}

const allMessages = {}
const locales = fs.readdirSync(localesDir).filter(f => fs.statSync(path.join(localesDir, f)).isDirectory())

for (const locale of locales) {
  console.log(`Bundling ${locale}...`)
  const localeDir = path.join(localesDir, locale)

  // Custom logic for AIRI's nested structure
  const base = yaml.load(fs.readFileSync(path.join(localeDir, 'base.yaml'), 'utf8'))
  const settings = yaml.load(fs.readFileSync(path.join(localeDir, 'settings.yaml'), 'utf8'))
  const stage = yaml.load(fs.readFileSync(path.join(localeDir, 'stage.yaml'), 'utf8'))

  const tamagotchiDir = path.join(localeDir, 'tamagotchi')
  const tamagotchiStage = yaml.load(fs.readFileSync(path.join(tamagotchiDir, 'stage.yaml'), 'utf8'))
  const tamagotchiSettings = yaml.load(fs.readFileSync(path.join(tamagotchiDir, 'settings.yaml'), 'utf8'))
  const tamagotchiTray = yaml.load(fs.readFileSync(path.join(tamagotchiDir, 'electron', 'tray.yaml'), 'utf8'))

  allMessages[locale] = {
    base,
    settings,
    stage,
    tamagotchi: {
      stage: tamagotchiStage,
      settings: tamagotchiSettings,
      electron: {
        tray: tamagotchiTray,
      },
    },
  }
}

const content = `// Auto-generated by scripts/bundle-i18n.js
const messages = ${JSON.stringify(allMessages, null, 2)}
messages['zh-CN'] = messages['zh-Hans']
messages['zh-TW'] = messages['zh-Hant']
export default messages
`
fs.writeFileSync(path.join(outputDir, 'messages.mjs'), content)
console.log('Bundle created at packages/i18n/src/dist-lite/messages.mjs')
